Assistant: \begin{align*}
\frac{\sqrt{x}}{\sqrt{x-1}} &= \frac{3}{2}\\
\left(\frac{\sqrt{x}}{\sqrt{x-1}}\right)^2 &= \left(\frac{3}{2}\right)^2 & \text{(Squaring both sides)}\\
\frac{x}{x-1} &= \frac{9}{4}\\
4x &= 9(x-1) & \text{(Cross-multiplying)}\\
4x &= 9x - 9\\
-5x &= -9\\
x &= \boxed{\frac{9}{5}}
\end{align*}

